function parsePdpBadge(value) {
  if (!value) return '';

  try {
    const parsed = JSON.parse(value);

    if (Array.isArray(parsed)) {
      return parsed
        .map(item => String(item).trim())
        .filter(Boolean)
        .join(', ');
    }

    return String(parsed).trim();
  } catch (e) {
    return String(value)
      .replace(/^\[/, '')
      .replace(/\]$/, '')
      .replace(/"/g, '')
      .replace(/\s*,\s*/g, ', ')
      .trim();
  }
}

function cleanText(value) {
  return String(value || '')
    .replace(/<[^>]*>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .replace(/\s+/g, ' ')
    .trim();
}

function extractZodiacSigns(title, description) {
  const zodiacSigns = [
    'Aries',
    'Taurus',
    'Gemini',
    'Cancer',
    'Leo',
    'Virgo',
    'Libra',
    'Scorpio',
    'Sagittarius',
    'Capricorn',
    'Aquarius',
    'Pisces',
  ];

  const combinedText = `${cleanText(title)} ${cleanText(description)}`;

  if (!combinedText.trim()) return '';

  if (/Zodiac Signs\s+Ideal\s+for\s+All/i.test(combinedText)) {
    return 'Ideal for All';
  }
  if(/Zodiac Signs\s+All\s+zodiac\s+signs/i.test(combinedText)) {
    return 'All zodiac signs';
  }

  const found = [];

  for (const sign of zodiacSigns) {
    const regex = new RegExp(`\\b${sign}\\b`, 'i');

    if (regex.test(combinedText)) {
      found.push(sign);
    }
  }

  return [...new Set(found)].join(', ');
}

function getResultFromInput(item) {
  let result = item.json?.data?.fetchShopifyData?.result;

  if (typeof result === 'string') {
    try {
      result = JSON.parse(result);
    } catch (e) {
      return null;
    }
  }

  return result;
}

const output = [];

for (const item of $input.all()) {
  const result = getResultFromInput(item);

  if (!result?.success || !Array.isArray(result.data)) continue;

  for (const product of result.data) {
    const title = String(product.title || '').trim();

    if (!title) continue;

    const productSubTitle = String(product.productSubTitle || '').trim();
    const problems = parsePdpBadge(product.pdpBadge || '');
    const zodiacSign = extractZodiacSigns(title, product.description || '');
    const price = String(product.price || '').trim();
    const available = String(product.available || '').trim();
    const url = String(product.url || '').trim();
    const imageUrl = String(product.image_url || '').trim();

    output.push({
  json: {
    title: title,
    productSubTitle: productSubTitle || 'N/A',
    problems: problems || 'N/A',
    zodiacSign: zodiacSign || 'N/A',
    price: price || 'N/A',
    available: available || 'N/A',
    url: url || 'N/A',
    image_url: imageUrl || 'N/A',
  },
});
  }
}

return output;

