const output = [];

function isEmptyValue(value) {
  const text = String(value || '').trim();

  return (
    text === '' ||
    text.toUpperCase() === 'N/A' ||
    text.toLowerCase() === 'null' ||
    text.toLowerCase() === 'undefined'
  );
}

function isNotAvailable(value) {
  const text = String(value || '').trim().toLowerCase();

  return (
    text === 'no' ||
    text === 'false' ||
    text === 'not available' ||
    text === 'out of stock' ||
    text === 'outofstock'
  );
}

for (const item of $input.all()) {
  const product = item.json;

  const title = String(product.title || '').trim();
  const productSubTitle = String(product.productSubTitle || '').trim();
  const problems = String(product.problems || '').trim();
  const zodiacSign = String(product.zodiacSign || '').trim();
  const price = String(product.price || '').trim();
  const available = String(product.available || '').trim();
  const url = String(product.url || '').trim();
  const imageUrl = String(product.image_url || '').trim();
  const noProductSubTitle = isEmptyValue(productSubTitle);
  const noProblems = isEmptyValue(problems);
  const noZodiacSign = isEmptyValue(zodiacSign);
  const productNotAvailable = isNotAvailable(available);

  const shouldRemove =
    noProductSubTitle &&
    noProblems &&
    noZodiacSign &&
    productNotAvailable;

  if (shouldRemove) {
    continue;
  }

  const text =
    `PRODUCT\n` +
    `Title: ${title || 'N/A'}\n` +
    `Product Sub Title: ${productSubTitle || 'N/A'}\n` +
    `Problems: ${problems || 'N/A'}\n` +
    `Zodiac Sign: ${zodiacSign || 'N/A'}\n` +
    `Price: ${price || 'N/A'}\n` +
    `Available: ${available || 'N/A'}\n` +
    `URL: ${url || 'N/A'}\n` +
    `Image URL: ${imageUrl || 'N/A'}`;

  output.push({
    json: {
      text,
    },
  });
}

return output;
